// =========================================================
//  ENTRY POINT: called from main.js navTo('manager')
// =========================================================
async function loadContestData(moduleKey, force = false, isPreload = false) {
    if (!isPreload) {
        ensureManagerShell();

        if (appState.isDirty && !confirm("Ungespeicherte Änderungen verwerfen?")) {
            const sel = document.getElementById('module-selector');
            if (sel) sel.value = appState.activeModule;
            return;
        }
    }

    const targetModule = moduleKey || appState.activeModule;

    if (!force && mailWizard.cachedModules[targetModule] && appState.members.length > 0) {
        if (!isPreload) {
            console.log("⚡ loadContestData: Lade aus lokalem Cache...");
            appState.activeModule = targetModule;
            const cached = mailWizard.cachedModules[targetModule];
            appState.teams = JSON.parse(JSON.stringify(cached.teams));
            appState.pool = JSON.parse(JSON.stringify(cached.pool));
            appState.isDirty = false;
            window.clearUnsaved();
            appState.mailList = [];
            renderContestUI();

            const sel = document.getElementById('module-selector');
            if (sel) sel.value = appState.activeModule;
        }
        return;
    }

    // Wenn Preload: Aktuellen Zustand im UI sichern, um ein Überschreiben zu verhindern
    const prevState = isPreload ? {
        activeModule: appState.activeModule,
        teams: JSON.parse(JSON.stringify(appState.teams)),
        pool: JSON.parse(JSON.stringify(appState.pool)),
        isDirty: appState.isDirty
    } : null;

    if (!isPreload) {
        appState.activeModule = targetModule;
        appState.isDirty = false;
        window.clearUnsaved();
        appState.mailList = [];
        renderLoadingState();
    } else {
        // Beim Preload setzen wir temporär das aktive Modul für processContestData
        appState.activeModule = targetModule;
    }

    const config = CONTEST_CONFIG[targetModule];

    try {
        const params = `action=getManagerData&sheetName=${encodeURIComponent(config.sheetName)}`;
        const res = await apiFetch('manager', params);

        const txt = await res.text();
        let data;
        try { data = JSON.parse(txt); }
        catch (e) { throw new Error("Backend-Antwort ist kein JSON (prüfe GAS Fehlerseite)"); }

        if (data.error) throw new Error(data.error);

        processContestData(data, config);
        
        // Deep-copy des geladenen Moduls cachen
        mailWizard.cachedModules[targetModule] = {
            teams: JSON.parse(JSON.stringify(appState.teams)),
            pool: JSON.parse(JSON.stringify(appState.pool))
        };

        if (!isPreload) {
            renderContestUI();

            if (!appState._dndInited) {
                initDragAndDrop();
                appState._dndInited = true;
            }

            const sel = document.getElementById('module-selector');
            if (sel) sel.value = appState.activeModule;
        }

    } catch (e) {
        if (!isPreload) {
            const c = document.getElementById('manager-inner');
            if (c) c.innerHTML = `<div class="col-12"><div class="alert alert-danger">Fehler: ${escapeHtml(e.message)}</div></div>`;
        } else {
            console.error(`Preload-Fehler für ${targetModule}:`, e);
        }
    } finally {
        if (isPreload && prevState) {
            // Zustand wiederherstellen
            appState.activeModule = prevState.activeModule;
            appState.teams = prevState.teams;
            appState.pool = prevState.pool;
            appState.isDirty = prevState.isDirty;
        }
    }
}

// =========================================================
//  TEARDOWN: called from main.js navTo() on view change
// =========================================================
function teardownManager() {
    appState._dndInited = false;
    appState.isDirty = false;
    const app = document.getElementById('manager-app');
    if (app) app.remove();
}


